mapper.select:
SELECT /** VocListMgmtMapper.selectVocListExcel */ TO_CHAR(VMM.RCP_ID) AS rcpId /* 접수ID */ , FN_GET_CODENM('CMN0032', JSI.PPPO) AS pppo /* 서비스구분(선불/후불) */ , NVL(VMM.TEL_NUM, ' ') AS telNum /* 가입고객 전화번호 */ , DECODE(VMM.CUSTOMER_ID, NULL, ' ', ( SELECT C.CUSTOMER_LINK_NAME FROM MSP_JUO_CUS_INFO C WHERE C.CUSTOMER_ID = VMM.CUSTOMER_ID ) ) AS custNm /* 가입고객명 */ , NVL(VMM.CUSTOMER_ID, ' ') AS customerId /* 가입고객 고객ID */ , NVL(VMM.CONTRACT_NUM, ' ') AS contractNum /* 가입고객 계약ID */ , VMM.CUST_YN AS custYn /* 고객여부 */ , FN_GET_CODENM('VOC0011', VMM.CUST_YN) AS custYnNm /* 고객여부명 */ , VMM.CUST_REL AS custRel /* 고객과 관계 */ , FN_GET_CODENM('VOC0013', VMM.CUST_REL) AS custRelNm /* 고객과 관계명 */ , NVL(VMM.REQ_CUST_NM, ' ') AS reqCustNm /* 요청고객명 */ , VMM.REQ_TEL_NUM AS reqTelNum /* 요청 전화번호 */ , VMM.REQ_ORGN_ID AS reqOrgnId /* 접수부서ID */ , FN_GET_ORGNM(VMM.REQ_ORGN_ID) AS reqOrgnNm /* 접수부서명 */ , VMM.REQR_ID AS reqrId /* 접수자ID */ , FN_GET_USRNM(VMM.REQR_ID) AS reqrNm /* 접수자명 */ , VMM.REQ_DTTM AS reqDttm /* 접수일자 */ , VMM.CNSL_MST_CD AS cnslMstCd /* 대분류 코드 */ , FN_GET_CODENM('VOC0001', VMM.CNSL_MST_CD) AS cnslMstNm /* 대분류명 */ , VMM.CNSL_MID_CD AS cnslMidCd /* 중분류 코드 */ , FN_GET_CODENM('VOC0002', VMM.CNSL_MID_CD) AS cnslMidNm /* 중분류명 */ , VMM.CNSL_DTL_CD AS cnslDtlCd /* 소분류 코드 */ , FN_GET_CODENM('VOC0003', VMM.CNSL_DTL_CD) AS cnslDtlNm /* 소분류명 */ , VMM.CNSL_STAT AS cnslStat /* 상담상태 코드 */ , FN_GET_CODENM('VOC0007', VMM.CNSL_STAT) AS cnslStatNm /* 상담상태 */ , VMM.PROC_ORGN_ID AS procOrgnId /* 처리부서ID */ , FN_GET_ORGNM(VMM.PROC_ORGN_ID) AS procOrgnNm /* 처리부서명 */ , NVL(VMM.PROCR_ID, ' ') AS procrId /* 처리자ID */ , NVL(FN_GET_USRNM(VMM.PROCR_ID), ' ') AS procrNm /* 처리자명 */ , VMM.PROC_DTTM AS procDttm /* 처리일시 */ , NVL(VMM.CMPL_ORGN_ID, ' ') AS cmplOrgnId /* 완료부서ID */ , NVL(FN_GET_ORGNM(VMM.CMPL_ORGN_ID), ' ') AS cmplOrgnNm /* 완료부서명 */ , NVL(VMM.CMPLR_ID, ' ') AS cmplrId /* 완료자ID */ , NVL(FN_GET_USRNM(VMM.CMPLR_ID), ' ') AS cmplrNm /* 완료자명 */ , NVL(VMM.CMPL_DTTM, ' ') AS cmplDttm /* 완료일시 */ , NVL(VMM.PROC_MM, 0) AS procMm /* 소요시간(분) */ , NVL(VMM.REQ_CNTT, ' ') AS reqCntt /* 요청내용 */ , NVL(VMM.RES_CNTT, ' ') AS resCntt /* 응대내용 */ , NVL(DTL.PROC_CNTT, ' ') AS procCntt /* 처리내용 */ , FN_GET_CODENM('RCP0063', JSI.PROD_TYPE) AS prodTypeNm /* 상품구분 */ , JSI.USER_SSN AS ssn , (SELECT CSTMR_TYPE FROM MSP_REQUEST WHERE CONTRACT_NUM = JSI.CONTRACT_NUM AND ROWNUM = 1) AS cstmrType , (SELECT B.RATE_NM FROM MSP_JUO_FEATURE_INFO A , MSP_RATE_MST B WHERE A.CONTRACT_NUM = VMM.CONTRACT_NUM AND A.SERVICE_TYPE = 'P' AND A.EVNT_TRTM_DT = ( SELECT MAX(EVNT_TRTM_DT) FROM MSP_JUO_FEATURE_INFO WHERE CONTRACT_NUM = A.CONTRACT_NUM AND SERVICE_TYPE = 'P' ) AND A.SOC = B.RATE_CD AND ROWNUM = 1) AS lstRateNm /* 현재요금제 */ , CASE WHEN JSI.PPPO = 'PP' THEN (SELECT ORGN_NM FROM ORG_ORGN_INFO_MST WHERE ORGN_ID = (SELECT AGENT_ID FROM PPS_CUSTOMER WHERE CONTRACT_NUM = JSI.CONTRACT_NUM)) ELSE (SELECT ORGN_NM FROM ORG_ORGN_INFO_MST WHERE ORGN_ID = JSI.OPEN_AGNT_CD) END AS orgnNm /* 개통대리점 */
, CASE WHEN VMM.CNSL_STAT <> 'COM' AND TO_DATE(TO_CHAR(TO_DATE(VMM.REQ_DTTM, 'YYYYMMDDHH24MISS') + 3, 'YYYYMMDD') || '173000', 'YYYYMMDDHH24MISS') < SYSDATE THEN '미준수' WHEN VMM.CNSL_STAT <> 'COM' THEN TO_CHAR(TRUNC((TO_DATE(TO_CHAR(TO_DATE(VMM.REQ_DTTM, 'YYYYMMDDHH24MISS') + 3, 'YYYYMMDD') || '173000', 'YYYYMMDDHH24MISS') - SYSDATE)*24*60)) ELSE CASE WHEN VMM.CMPL_DTTM <= TO_CHAR(TO_DATE(VMM.REQ_DTTM, 'YYYYMMDDHH24MISS') + 3, 'YYYYMMDD') || '173000' THEN '준수' ELSE '미준수' END END AS remainMm /* 잔여시간(분) */
FROM MSP_VOC_MGMT_MST VMM , MSP_JUO_SUB_INFO JSI , MSP_VOC_MGMT_DTL DTL WHERE 1 = 1 AND VMM.RCP_ID = DTL.RCP_ID AND DTL.PROC_DTTM = (SELECT MAX(PROC_DTTM) FROM MSP_VOC_MGMT_DTL WHERE RCP_ID = VMM.RCP_ID ) AND VMM.CONTRACT_NUM = JSI.CONTRACT_NUM(+)
AND JSI.PPPO = 'PP'
AND (JSI.PPPO = 'PO' OR JSI.PPPO IS NULL)
AND VMM.REQ_DTTM BETWEEN #{regStartDt} || '000000' AND #{regEndDt} || '235959'
AND NVL(VMM.CMPL_DTTM, 1) >= DECODE(VMM.CMPL_DTTM, NULL, 1, #{comStartDt} || '000000') AND NVL(VMM.CMPL_DTTM, 1) <= DECODE(VMM.CMPL_DTTM, NULL, 1, #{comEndDt} || '235959')
AND VMM.REQ_ORGN_ID = #{reqOrgnId} /* 접수부서 */
AND VMM.REQR_ID = #{reqrId} /* 접수자 */
AND VMM.PROC_ORGN_ID = #{procOrgnId} /* 처리부서 */
AND VMM.PROCR_ID = #{procrId} /* 처리자 */
AND VMM.CMPL_ORGN_ID = #{cmplOrgnId} /* 완료부서 */
AND VMM.CMPLR_ID = #{cmplrId} /* 완료자 */
AND VMM.CNSL_MST_CD = #{cnslMstCd} /* 상담대분류 */
AND VMM.CNSL_MID_CD = #{cnslMidCd} /* 상담중분류 */
AND VMM.CNSL_DTL_CD = #{cnslDtlCd} /* 상담소분류 */
AND VMM.CNSL_STAT = #{cnslStat} /* 상담상태 */
/* 3시간 이내 */ AND VMM.PROC_MM < (60*3)
/* 6시간 이내 */ AND VMM.PROC_MM < (60*6)
/* 12시간 이내 */ AND VMM.PROC_MM < (60*12)
/* 24시간 이내 */ AND VMM.PROC_MM < (60*24)
/* 48시간 이내 */ AND VMM.PROC_MM < (60*24*2)
/* D+3일 이내 */ AND VMM.PROC_MM < (60*24*4)
/* D+4일 이후 */ AND VMM.PROC_MM >= (60*24*4)
AND JSI.PROD_TYPE = #{prodType}
/* 24시간 이내 */
AND VMM.CNSL_STAT <> 'COM' AND TRUNC((TO_DATE(TO_CHAR(TO_DATE(VMM.REQ_DTTM, 'YYYYMMDDHH24MISS') + 3, 'YYYYMMDD') || '1730', 'YYYYMMDDHH24MISS') - SYSDATE) * 24 * 60) BETWEEN 0 AND ( CASE WHEN TO_CHAR(SYSDATE, 'HH24MISS') <= '173000' THEN (60*24*#{remainMm}) + TRUNC((TO_DATE(TO_CHAR(SYSDATE, 'YYYYMMDD') || '173000', 'YYYYMMDDHH24MISS') - SYSDATE)*24*60) ELSE (60*24*#{remainMm}) - TRUNC((TO_DATE(TO_CHAR(SYSDATE, 'YYYYMMDD') || '173000', 'YYYYMMDDHH24MISS') - SYSDATE)*24*60) END )
/* 미준수 */
AND VMM.CNSL_STAT <> 'COM' AND TO_DATE(TO_CHAR(TO_DATE(VMM.REQ_DTTM, 'YYYYMMDDHH24MISS') + 3, 'YYYYMMDD') || '173000', 'YYYYMMDDHH24MISS') < SYSDATE
ORDER BY VMM.RCP_ID DESC
